        let mod = prefix[j]
        if last_pos.has_key(mod) {
            let i = last_pos[mod]
            let sum = prefix[j] - prefix[i]
            if sum % k == 0 {
                let subarray_sum = prefix[j] - prefix[i]
                total_sum = total_sum - subarray_sum
                if total_sum < min_sum {
                    min_sum = total_sum
                }
                last_pos.clear()
                last_pos[0] = j
                prefix[j] = 0
            }
        } else {
            last_pos[mod] = j
        }
    }

    return min_sum
}
