func solve(nums: Array<Int64>, k: Int64) -> Int64 {
    let n = nums.count
    var prefixSum = Array(repeating: Int64(0), count: n + 1)
    for i in 0..<n {
        prefixSum[i + 1] = prefixSum[i] + nums[i]
    }

    var remainderIndices = [Int64: Int]()
    remainderIndices[0] = 0
    var dp = Array(repeating: Int64(0), count: n + 1)

    for i in 1...n {
        let remainder = prefixSum[i] % k
        if let prevIndex = remainderIndices[remainder] {
            dp[i] = max(dp[i - 1], dp[prevIndex] + prefixSum[i] - prefixSum[prevIndex])
        } else {
            dp[i] = dp[i - 1]
        }
        remainderIndices[remainder] = i
    }

    return prefixSum[n] - dp[n]
}
